solutions.cpp:
#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> divisors(int n) {
        vector<int> divs;
        for (int i = 1; i <= n; i++) {
            if (n % i == 0) {
                divs.push_back(i);
            }
        }
        return divs;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int _;
    if (!(cin >> _)) return 0;
    int n;
    if (!(cin >> n)) return 0;
    Solution sol;
    vector<int> ans = sol.divisors(n);
    cout << ans.size() << "\n";
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : "\n");
    }
    cout << "\n";
    return 0;
}
